<script setup>defineProps({log:{type:Object,required:true},tracker:{type:Object,default:null},open:Boolean});defineEmits(['close','track'])</script>
<template><aside v-if="tracker" class="tracker"><strong>{{ tracker.name }}</strong><small>{{ tracker.stage }}</small><p v-for="o in tracker.objectives" :key="o.name" :class="{done:o.completed}">{{ o.completed?'✓':'○' }} {{ o.name }} <span v-if="o.required>1">{{ o.current }}/{{ o.required }}</span><em v-if="o.optional"> Optional</em></p></aside><div v-if="open" class="backdrop" @click.self="$emit('close')"><section class="log" role="dialog" aria-modal="true"><header><h2>Quest Log</h2><button @click="$emit('close')">×</button></header><template v-for="(rows,status) in log" :key="status"><h3>{{ status }}</h3><p v-if="!rows.length">No quests.</p><article v-for="q in rows" :key="q.instanceId"><div><strong>{{ q.name }}</strong><small>{{ q.category }} · {{ q.stageName }}</small></div><p>{{ q.description }}</p><ul><li v-for="o in q.objectives" :key="o.name">{{ o.status==='Completed'?'✓':'○' }} {{ o.name }} <em v-if="o.optional">Optional</em><span v-if="o.required>1"> {{ o.current }}/{{ o.required }}</span></li></ul><button v-if="status==='Active'" @click="$emit('track',q.instanceId)">{{ q.tracked?'Tracked':'Track' }}</button></article></template></section></div></template>
<style scoped>.tracker{position:absolute;right:1rem;top:5rem;z-index:15;width:260px;padding:.75rem;border:1px solid #64748b;border-radius:10px;background:#0f172ae6;color:#e2e8f0}.tracker small,.tracker p{display:block;margin:.25rem 0}.tracker .done{color:#86efac}.tracker em{color:#facc15}.backdrop{position:fixed;inset:0;z-index:85;display:grid;place-items:center;background:#020617cc}.log{width:min(780px,95vw);max-height:90vh;overflow:auto;padding:1rem;border:1px solid #64748b;border-radius:12px;background:#0f172a;color:#e2e8f0}.log header,.log article>div{display:flex;justify-content:space-between}.log article{margin:.7rem 0;padding:1rem;border:1px solid #334155;border-radius:8px}.log small{display:block;color:#94a3b8}</style>
